return [{ json: { context } }];

const prev = $items('After Heartbeat Task')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const afterLease = result.lease_expires_at || null;
let extended = false;
if (prev.lease_before && afterLease) {
  extended = new Date(afterLease).getTime() > new Date(prev.lease_before).getTime();
}
const ok = !!result.id && (prev.lease_before ? extended : true);
const error = result.error || result.message || null;

const testResult = {
  name: 'heartbeat_extends_lease',
  success: ok && !error,
  expected: 'lease_expires_at increases after heartbeat_task',
  actual: { before: prev.lease_before, after: afterLease },
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{ json: { context } }];

