const context = { ...prev, results: [...prev.results, testResult] };

return [{ json: { context } }];

const prev = $items('After Worker Heartbeat')[0].json.context;
const items = $input.all();
const queueNames = items.map(i => i.json.queue_name).filter(Boolean);
const ok = queueNames.length > 0;
const error = items[0]?.json?.error || items[0]?.json?.message || null;

const testResult = {
  name: 'get_queue_stats',
  success: ok && !error,
  expected: 'queue stats returned',
  actual: items.map(i => i.json),
  error
};

const results = [...prev.results, testResult];
const passed = results.filter(r => r.success).length;
const failed = results.length - passed;

return [{
  json: {
    run_id: prev.run_id,
    queue_name: prev.queue_name,
    worker_id: prev.worker_id,
    api_key_prefix: prev.api_key ? String(prev.api_key).slice(0, 10) : null,
    summary: { total: results.length, passed, failed },
    results
  }
}];
